const ERROR_LOG_MAX = 20;

function errorLogKey(){ return AppState.currentUser ? `mx_errlog_${AppState.currentUser.uid}` : 'mx_errlog_anon'; }

function currentTabName(){
  const el = document.querySelector('#nav-shifts.active, #nav-finance.active, #nav-debt.active, #nav-shopping.active, #nav-settings.active');
  return el ? el.id.replace('nav-','') : null;
}

function logAppError(kind, detail){
  const entry = { kind, at: new Date().toISOString(), tab: currentTabName(), ...detail };
  console.error(`[Zminka:${kind}]`, entry);
  try{
    const key = errorLogKey();
    const list = JSON.parse(localStorage.getItem(key) || '[]');
    list.push(entry);
    while(list.length > ERROR_LOG_MAX) list.shift();
    localStorage.setItem(key, JSON.stringify(list));
  }catch(e){}
}

export const SALARY_GOAL = 20000;

export function subKey(type,name){ return type+':'+name; }

// rates/converter/analytics moved into #tools-modal (see CLAUDE.md's
// Finance-tab-widgets section) — no longer part of the toggleable
// show/hide+reorder set, so only chart/goals remain here.
const WIDGET_SECTION_IDS={chart:'finance-chart-section', goals:'goals-section'};

export function sanitizeWidgetOrder(arr){
  const seen=new Set();
  const out=(Array.isArray(arr)?arr:[]).filter(k=>WIDGET_ORDER_DEFAULT.includes(k)&&!seen.has(k)&&seen.add(k));
  WIDGET_ORDER_DEFAULT.forEach(k=>{ if(!seen.has(k)){ out.push(k); seen.add(k); } });
  return out;
}

export function applyWidgetVisibility(){
  Object.entries(WIDGET_SECTION_IDS).forEach(([key,id])=>{
    if(key==='goals') return; // goals additionally self-hides when empty — handled inside renderGoals()
    const el=document.getElementById(id);
    if(el) el.style.display = AppState.widgets[key]===false ? 'none' : '';
  });
  renderGoals();
  applyWidgetOrder();
}

export function applyWidgetOrder(){
  const anchor=document.getElementById('budgets-section');
  if(!anchor||!anchor.parentNode) return;
  AppState.widgetOrder.forEach(key=>{
    const el=document.getElementById(WIDGET_SECTION_IDS[key]);
    if(el) anchor.parentNode.insertBefore(el, anchor);
  });
}

const FREE_LIMITS = {wallets:3, categoriesPerType:8, autoRules:3, recurring:3, goals:1};

function isPremium(){ return AppState.subscription.plan==='premium' && (!AppState.subscription.expiresAt || AppState.subscription.expiresAt>Date.now()); }

function canAddMore(kind, currentCount){ return isPremium() || currentCount < FREE_LIMITS[kind]; }

export function renderPremiumUI(){
  const sub=document.getElementById('settings-premium-sub');
  if(sub) sub.textContent = isPremium() ? tr('premium_active_plan') : tr('premium_free_plan');
}

const PREMIUM_LIMIT_MSG_KEYS={wallets:'premium_limit_wallets', categoriesPerType:'premium_limit_categories', autoRules:'premium_limit_rules', recurring:'premium_limit_recurring', goals:'premium_limit_goals'};

const showPremiumUpsell = function(limitKind){
  const msgEl=document.getElementById('premium-modal-limit-msg');
  if(msgEl) msgEl.textContent = limitKind ? tr(PREMIUM_LIMIT_MSG_KEYS[limitKind]) : tr('premium_subtitle');
  document.getElementById('premium-modal').style.display='flex';
};

export const DEBT_COLORS = ['#8b5cf6','#10b981','#3b82f6','#f59e0b','#ec4899','#06b6d4'];

export const PALETTE = ['#8b5cf6','#3b82f6','#10b981','#f59e0b','#ec4899','#06b6d4','#ef4444','#a78bfa'];

export function categoryColor(name){
  const s=String(name||'');
  let h=0;
  for(let i=0;i<s.length;i++) h=(h*31+s.charCodeAt(i))>>>0;
  return PALETTE[h%PALETTE.length];
}

function populateMonthSelectLabels(){
  const ms=document.getElementById('select-month');
  if(!ms) return;
  Array.from(ms.options).forEach(o=>{ o.textContent=AppState.MONTHS[Number(o.value)]; });
  csSync(ms);
}

const __applyLangDynamic = function(lang){
  AppState.MONTHS=LANG_CALENDAR[lang].months;
  AppState.MONTHS_SHORT=LANG_CALENDAR[lang].monthsShort;
  AppState.WEEKDAYS=LANG_CALENDAR[lang].weekdays;
  populateMonthSelectLabels();
  renderCalendar(); renderIncomeChart(); renderFinance(); renderFinanceChart(); renderDebt();
  renderProfileUI(); renderPremiumUI(); renderNotifUI(); updateAmountLabel();
  const wsl=document.getElementById('wallet-source-label');
  if(wsl){
    const key={income:'finance_wallet',expense:'finance_wallet_expense',transfer:'finance_wallet_transfer'}[AppState.currentFinanceType];
    if(key) wsl.textContent=tr(key);
  }
};

const CAT_ICON = {
  'Зарплата':'briefcase','Аванс':'card','Підробіток':'gift','Повернення боргу':'coin','Інше':'box',
  'Кава':'coffee','Кафе':'coffee','Фастфуд':'burger','Розваги':'gift',
  'Кредит':'bank','Борг':'coin','Продукти':'cart','Транспорт':'car','Комуналка':'house','Покупки':'bag',
  'Здоров\'я':'coin','Аптека':'coin','Цигарки':'cigarette','Внутрішній переказ':'swap',
};

// 'umbrella' deliberately excluded — it's used elsewhere for vacation/day-off
// (setIcon('ic-vacation','umbrella')), which reads fine there, but as a
// random fallback for an arbitrary category name (e.g. a bank fee category
// hashing onto it) it looks nonsensical with no thematic connection.
const CAT_ICON_FALLBACK_POOL = ['tag','person','star','flag','bell','globe','camera','box','gift'];

export function categoryIcon(name){
  if(CAT_ICON[name]) return CAT_ICON[name];
  const s=String(name||'');
  let h=0;
  for(let i=0;i<s.length;i++) h=(h*31+s.charCodeAt(i))>>>0;
  return CAT_ICON_FALLBACK_POOL[h%CAT_ICON_FALLBACK_POOL.length];
}

