// Top-level statements that DO something immediately (as opposed to a
// plain declaration) - deferred into this function and called from
// app.js only after every module in the import graph has finished
// evaluating, so nothing here can hit a temporal-dead-zone reference to
// another chunk's not-yet-initialized export (this is exactly the class
// of bug that broke 'auth' being read before core.js's declaration of it
// had run, when this was still ordinary top-level code in this file).
export function __init_core__(){
window.addEventListener('error', e=>{
  logAppError('uncaught-error', { message: e.message, source: e.filename, line: e.lineno, col: e.colno, stack: e.error && e.error.stack });
});
window.addEventListener('unhandledrejection', e=>{
  const reason = e.reason;
  logAppError('unhandled-rejection', { message: reason && reason.message || String(reason), stack: reason && reason.stack });
});
// Surfaces Content-Security-Policy-Report-Only violations (see
// firebase.json) into the same local error log, since this app has no
// backend to send CSP reports to — lets the account owner check
// localStorage (or a future Settings-tab viewer) for anything the policy
// missed before it ever gets flipped from report-only to enforcing.
document.addEventListener('securitypolicyviolation', e=>{
  logAppError('csp-violation', { message: `${e.violatedDirective} blocked ${e.blockedURI}`, source: e.sourceFile, line: e.lineNumber, col: e.columnNumber });
});
// window.__applyLangDynamic deliberately kept — it's the one hook back
// from the inline classic script's setLang() (genuinely outside the js/
// module graph, see CLAUDE.md's "index.html script structure"), not an
// onclick attribute, so it's out of scope for this audit item.
window.__applyLangDynamic = __applyLangDynamic;
// Phase 13 of the window.*/inline-onclick removal audit item (see
// CLAUDE.md): this file's one static onclick="" site in index.html
// (the premium-upsell settings row) converted to a data-action dispatch.
// window.getErrorLog was dropped outright — grepped every call site
// across index.html/js/*.js and found zero, dead since whenever this
// file was split out.
const CLICK_ACTIONS = {
  'show-premium-upsell': ()=>showPremiumUpsell(),
};
document.addEventListener('click', e=>{
  const el=e.target.closest('[data-action]');
  if(el && CLICK_ACTIONS[el.dataset.action]) CLICK_ACTIONS[el.dataset.action](el.dataset);
}, true);
}

